  }}
  SimParam(Axis := Axis,
           Execute := BOOL#TRUE,
           ParameterNumber := 1000, 
           Value := BOOL#TRUE);
  VelParam(Axis := Axis,
           Execute := BOOL#TRUE,
           ParameterNumber := 9,
           Value := MaxVel);
  AccParam(Axis := Axis, 
           Execute := BOOL#TRUE,
           ParameterNumber := 13,
           Value := MaxAcc);
  DecParam(Axis := Axis,
