  int res=__MK_Alloc_MC_TRIGGER_REF(); 
  if(res>=0) 
      *__MK_GetPublic_MC_TRIGGER_REF(res)=
         (GetFbVar(POSITIVEEDGE) ? 0x01 : 0)
        |(GetFbVar(NEGATIVEEDGE) ? 0x02 : 0);
  SetFbVar(TRIGGERINPUT,res); 
  }}
  Done := TRUE;
END_IF;

